import{toNodes,parentsOf,lastOfLevel,countExpanded}from"./utils";describe("bug_#7",()=>{let l;test("setup",()=>{l=toNodes([{label:"0",expand:!0,children:[{label:"00",expand:!0,children:["000","001"]},{label:"01",children:["010","011"]}]},"1"]),expect(l.length).toBe(8),expect(l.map(e=>e.label)).toEqual(["0","00","000","001","01","010","011","1"])}),test("parents",()=>{var e=(e,...t)=>expect(parentsOf(e,l).map(e=>e.label)).toEqual(t);e(l[0],"0"),e(l[1],"0","00"),e(l[2],"0","00","000"),e(l[3],"0","00","001")}),test("lastOfLevel",()=>{var e=(e,t)=>expect(lastOfLevel(e,l).label).toEqual(t);e(l[0],"1"),e(l[1],"01"),e(l[2],"001")}),test("countExpanded",()=>{var e=(e,t)=>expect(countExpanded(e)).toBe(t);e(l[0],3),e(l[1],2),e(l[2],1)})});